/* ============================================
   إعلانات أخرى - Other Ad Positions
   أسفل الهيدر - فوق المحتوى - منتصف المقال - أسفل المقال
   ============================================ */

/* موضع الإعلان أسفل الهيدر */
.ad-below-header {
  margin: 20px 0;
  padding: 0 20px;
  width: 100%;
  max-width: 100%;
  text-align: center;
  clear: both;
  overflow: hidden;
  min-height: 90px; /*防止 CLS */
}

/* موضع الإعلان فوق المحتوى الرئيسي */
.ad-above-content {
  margin: 20px 0 30px;
  padding: 0 20px;
  width: 100%;
  max-width: 100%;
  text-align: center;
  clear: both;
  overflow: hidden;
  min-height: 90px; /*防止 CLS */
}

/* موضع الإعلان في منتصف المقال */
.ad-in-article {
  margin: 35px 0;
  padding: 20px;
  width: 100%;
  max-width: 100%;
  text-align: center;
  clear: both;
  overflow: hidden;
  background: linear-gradient(135deg, #f8f9fa 0%, #eef2f7 100%);
  border-radius: var(--border-radius);
  border: 1px dashed var(--border-color);
}

/* موضع الإعلان أسفل المقال - تصميم محسن ومتجاوب */
.ad-below-post {
  margin: 40px 0;
  padding: 25px;
  width: 100%;
  max-width: 100%;
  text-align: center;
  clear: both;
  overflow: hidden;
  background: linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%);
  border-radius: 16px;
  box-sizing: border-box;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.06);
  border: 1px solid rgba(99, 102, 241, 0.12);
  position: relative;
  z-index: 1;
}

/* للشاشات الكبيرة - عرض مناسب مع منع التداخل مع القائمة الجانبية */
@media (min-width: 1200px) {
  .ad-below-post {
    max-width: 100%;
    margin: 50px 0;
    margin-left: 0;
    grid-column: 1 !important;
  }
}

/* شاشات أكبر - تقليدية */
@media (min-width: 1400px) {
  .ad-below-post {
    max-width: 100%;
  }
}

/* شاشات 992px - 1199px */
@media (min-width: 992px) and (max-width: 1199px) {
