    max-width: 100%;
  }
}

/* للشاشات المتوسطة */
@media (max-width: 768px) {
  .ad-below-post {
    margin: 25px 0;
    padding: 20px 15px;
    border-radius: 12px;
  }
}

/* للشاشات الصغيرة جداً */
@media (max-width: 480px) {
  .ad-below-post {
    margin: 20px 0;
    padding: 15px 12px;
    border-radius: 10px;
  }
}

