/* ============================================
   نهاية نظام الإعلانات المتجاوب
   ============================================ */

/* ============================================
   صفحة الخطأ 404 - الصفحة غير موجودة
   ============================================ */
.error-404-page {
  /* display: none; - تم تعطيل هذا لأن الصفحة يجب أن تظهر عند الخطأ */
  text-align: center;
  padding: 80px 20px;
  min-height: calc(100vh - 300px);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

.error-404-icon {
  width: 120px;
  height: 120px;
  margin-bottom: 30px;
  animation: errorFloat 3s ease-in-out infinite;
}

@keyframes errorFloat {
  0%, 100% { transform: translateY(0) scale(1); }
  50% { transform: translateY(-10px) scale(1.05); }
}

@keyframes errorPulse {
  0%, 100% { transform: scale(1); opacity: 1; }
  50% { transform: scale(1.05); opacity: 0.8; }
}

.error-404-icon svg {
  width: 100%;
  height: 100%;
  fill: var(--accent-color);
}

.error-404-title {
  font-size: 48px;
  font-weight: 800;
  color: var(--primary-color);
  margin-bottom: 15px;
  line-height: 1.2;
}

.error-404-code {
  font-size: 120px;
  font-weight: 900;
  background: var(--accent-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 10px;
  line-height: 1;
}

.error-404-message {
  font-size: 20px;
  color: var(--text-light);
  margin-bottom: 30px;
  max-width: 500px;
  line-height: 1.6;
}

.error-404-suggestion {
  font-size: 16px;
  color: var(--text-light);
  margin-bottom: 40px;
  line-height: 1.6;
}

.error-404-actions {
  display: flex;
  gap: 15px;
  flex-wrap: wrap;
  justify-content: center;
}

.error-404-btn {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 14px 32px;
  border-radius: var(--border-radius);
  font-size: 16px;
  font-weight: 600;
  text-decoration: none;
  transition: var(--transition);
  cursor: pointer;
  border: none;
}

.error-404-btn-primary {
  background: var(--accent-gradient);
  color: white;
}

.error-404-btn-primary:hover {
  transform: translateY(-3px);
  box-shadow: var(--shadow-hover);
  color: white;
}

.error-404-btn-secondary {
  background: var(--light-gray);
  color: var(--text-dark);
}

.error-404-btn-secondary:hover {
  background: var(--medium-gray);
  color: var(--text-dark);
}

.error-404-btn svg {
  width: 20px;
  height: 20px;
}

/* رابط الخريطة الصوتية */
.error-404-sitemap {
  margin-top: 20px;
}

.error-404-sitemap a {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  color: var(--accent-color);
  font-weight: 500;
}

.error-404-sitemap a:hover {
  color: var(--primary-color);
}

.error-404-sitemap svg {
  width: 18px;
  height: 18px;
  fill: currentColor;
}

.error-404-search {
  margin-top: 40px;
  width: 100%;
  max-width: 500px;
}

.error-404-search-form {
  display: flex;
  gap: 10px;
}

.error-404-search-input {
  flex: 1;
  padding: 14px 20px;
  border: 2px solid var(--border-color);
  border-radius: var(--border-radius);
  font-size: 16px;
  font-family: var(--font-primary);
  transition: var(--transition);
  outline: none;
}

.error-404-search-input:focus {
  border-color: var(--accent-color);
}

.error-404-search-btn {
  padding: 14px 24px;
  background: var(--accent-gradient);
  color: white;
  border: none;
  border-radius: var(--border-radius);
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
}

.error-404-search-btn:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow);
}

/* Responsive for 404 page */
@media screen and (max-width: 992px) {
  .error-404-page {
    height: auto;
    min-height: auto;
  }
}

@media (max-width: 768px) {
  .error-404-page {
    padding: 40px 20px;
  }
  
  .error-404-code {
    font-size: 80px;
  }
  
  .error-404-title {
    font-size: 28px;
  }
  
  .error-404-message {
    font-size: 16px;
  }
  
  .error-404-actions {
    flex-direction: column;
    width: 100%;
  }
  
  .error-404-btn {
    width: 100%;
    justify-content: center;
  }
  
  .error-404-search-form {
    flex-direction: column;
  }
  
  .error-404-icon {
    width: 80px;
    height: 80px;
  }
}

/* ============================================
   رسالة الصفحة الفارغة - Empty State Message
   ============================================ */
.empty-state-message {
  text-align: center;
  padding: 80px 20px;
  min-height: calc(100vh - 300px);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

.empty-state-icon {
  width: 120px;
  height: 120px;
  margin-bottom: 30px;
  animation: emptyFloat 3s ease-in-out infinite;
}

@keyframes emptyFloat {
  0%, 100% { transform: translateY(0) scale(1); }
  50% { transform: translateY(-10px) scale(1.05); }
}

.empty-state-icon svg {
  width: 100%;
  height: 100%;
  fill: var(--accent-color);
}

.empty-state-title {
  font-size: 32px;
  font-weight: 700;
  color: var(--primary-color);
  margin-bottom: 15px;
  line-height: 1.3;
}

.empty-state-text {
  font-size: 18px;
  color: var(--text-light);
  margin-bottom: 15px;
  max-width: 500px;
  line-height: 1.7;
}

.empty-state-actions {
  display: flex;
  gap: 15px;
  flex-wrap: wrap;
  justify-content: center;
  margin-top: 30px;
}

.empty-state-btn {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 14px 32px;
  border-radius: var(--border-radius);
  font-size: 16px;
  font-weight: 600;
  text-decoration: none;
  transition: var(--transition);
  cursor: pointer;
  border: none;
}

.empty-state-btn-primary {
  background: var(--accent-gradient);
  color: white;
}

.empty-state-btn-primary:hover {
  transform: translateY(-3px);
  box-shadow: var(--shadow-hover);
  color: white;
}

.empty-state-btn-secondary {
  background: var(--light-gray);
  color: var(--text-dark);
}

.empty-state-btn-secondary:hover {
  background: var(--medium-gray);
  color: var(--text-dark);
}

.empty-state-btn svg {
  width: 20px;
  height: 20px;
}

.empty-state-suggestions {
  margin-top: 40px;
  padding-top: 30px;
  border-top: 1px solid var(--border-color);
}

.empty-state-suggestions h3 {
  font-size: 18px;
  font-weight: 600;
  color: var(--primary-color);
  margin-bottom: 20px;
}

.empty-state-suggestions ul {
  list-style: none;
  display: flex;
  gap: 20px;
  justify-content: center;
  flex-wrap: wrap;
}

.empty-state-suggestions li a {
  color: var(--accent-color);
  font-weight: 500;
  padding: 8px 16px;
  border-radius: var(--border-radius-sm);
  background: var(--light-gray);
  transition: var(--transition);
}

.empty-state-suggestions li a:hover {
  background: var(--accent-color);
  color: white;
}

/* تنسيقات البحث في الصفحة الفارغة */
.empty-state-search {
  margin-top: 30px;
  width: 100%;
  max-width: 500px;
}

.empty-state-search-form {
  display: flex;
  gap: 10px;
}

.empty-state-search-input {
  flex: 1;
  padding: 14px 20px;
  border: 2px solid var(--border-color);
  border-radius: var(--border-radius);
  font-size: 16px;
  font-family: var(--font-primary);
  transition: var(--transition);
  outline: none;
}

.empty-state-search-input:focus {
  border-color: var(--accent-color);
}

.empty-state-search-btn {
  padding: 14px 24px;
  background: var(--accent-gradient);
  color: white;
  border: none;
  border-radius: var(--border-radius);
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
}

.empty-state-search-btn:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow);
}

/* استجابة للجوال */
@media (max-width: 768px) {
  .empty-state-message {
    padding: 40px 20px;
  }
  
  .empty-state-title {
    font-size: 24px;
  }
  
  .empty-state-text {
    font-size: 16px;
  }
  
  .empty-state-actions {
    flex-direction: column;
    width: 100%;
  }
  
  .empty-state-btn {
    width: 100%;
    justify-content: center;
  }
  
  .empty-state-icon {
    width: 80px;
    height: 80px;
  }
  
  .empty-state-suggestions ul {
    flex-direction: column;
    gap: 10px;
  }
  
  .empty-state-search-form {
    flex-direction: column;
  }
}

/* Hide sidebar on empty state page */
.empty-state-message ~ .sidebar,
body.empty-label-page .sidebar,
body.empty-search-page .sidebar,
body.empty-label-page .ad-section,
body.empty-search-page .ad-section,
body.empty-label-page .ad-sidebar,
body.empty-search-page .ad-sidebar,
body.empty-label-page .ad-container,
body.empty-search-page .ad-container {
  display: none !important;
}

/* Full width on empty state page */
body.empty-label-page #sidepar-wid,
body.empty-label-page #sidebar-wids,
body.empty-label-page .sidebar,
body.empty-label-page aside,
body.empty-search-page #sidepar-wid,
body.empty-search-page #sidebar-wids,
body.empty-search-page .sidebar,
body.empty-search-page aside {
  display: none !important;
}

/* Make main content full width on empty state */
body.empty-label-page .main-content,
body.empty-label-page .posts-section,
body.empty-label-page .blog-posts-wrapper,
body.empty-search-page .main-content,
body.empty-search-page .posts-section,
body.empty-search-page .blog-posts-wrapper {
  width: 100% !important;
  max-width: 100% !important;
  padding: 0 !important;
  margin: 0 !important;
}

body.empty-label-page .main-layout,
body.empty-search-page .main-layout {
  display: block !important;
}

body.empty-label-page .main-layout > *,
body.empty-search-page .main-layout > * {
  display: none;
}

/* إلا رسالة الحالة الفارغة */
body.empty-label-page .main-layout > .empty-state-message,
body.empty-search-page .main-layout > .empty-state-message,
body.empty-label-page .empty-state-message,
body.empty-search-page .empty-state-message {
  display: flex !important;
}

body.empty-label-page .empty-state-message,
body.empty-search-page .empty-state-message {
  display: flex !important;
}

/* Hide sidebar and ads on 404 error page */
body.error-page .sidebar,
body.error-page #sidepar-wid,
body.error-page #sidebar-wids,
body.error-page aside,
body.error-page .ad-section,
body.error-page .ad-sidebar,
body.error-page .ad-container {
  display: none !important;
}

/* Hide sidebar and ads on static pages (/p/xxx.html or /xxx.html) */
body.static-page .sidebar,
body.static-page #sidepar-wid,
body.static-page #sidebar-wids,
body.static-page aside,
body.static-page .ad-section,
body.static-page .ad-sidebar,
body.static-page .ad-container {
  display: none !important;
}

/* Full width on static pages - hide sidebar */
body.static-page .main-content,
body.static-page .posts-section,
body.static-page .blog-posts-wrapper {
  width: 100% !important;
  max-width: 100% !important;
}

body.static-page .main-layout {
  display: block !important;
}

body.static-page .main-layout > * {
  display: none;
}

body.static-page .main-layout .posts-section {
  display: block !important;
}

/* Full width on 404 page - hide sidebar section */
body.error-page #sidepar-wid,
body.error-page #sidebar-wids,
body.error-page .sidebar,
body.error-page aside {
  display: none !important;
}

/* Make main content full width on 404 */
body.error-page .main-content,
body.error-page .posts-section,
body.error-page .blog-posts-wrapper {
  width: 100% !important;
  max-width: 100% !important;
  padding: 0 !important;
  margin: 0 !important;
}

body.error-page .main-layout,
body.static-page .main-layout {
  display: block !important;
  grid-template-columns: 1fr !important;
}

body.error-page .main-layout > *,
body.static-page .main-layout > * {
  display: none;
}

body.error-page .main-layout .posts-section {
  display: block !important;
  width: 100% !important;
  max-width: 100% !important;
}

/* Full width container for 404 page */
body.error-page .posts-section {
  width: 100% !important;
  max-width: 100% !important;
  padding: 0 !important;
}

body.error-page .container {
  max-width: 100% !important;
  padding: 0 40px !important;
}

/* Also handle via body class */
body:has(.error-404-page) .sidebar,
html:has(.error-404-page) .sidebar {
  display: none !important;
}

/* Handle empty label/search pages - show error page, hide other content */
.error-404-page,
.empty-state-message {
  display: flex !important;
  visibility: visible !important;
  opacity: 1 !important;
  position: relative !important;
  z-index: 9999 !important;
  width: 100% !important;
  min-height: 60vh !important;
  background: white !important;
  margin: 0 !important;
  padding: 80px 20px !important;
  box-sizing: border-box !important;
}

/* Hide blog-posts-wrapper when empty */
body.empty-label-page .blog-posts-wrapper,
body.empty-search-page .blog-posts-wrapper {
  display: none !important;
}

/* Force show error page on empty label/search */
.empty-label-page .error-404-page,
.empty-search-page .error-404-page,
.empty-label-page .empty-state-message,
.empty-search-page .empty-state-message {
  display: flex !important;
  visibility: visible !important;
  opacity: 1 !important;
}

