/* أنماط وضع التخطيط - تصميم بسيط وجميل */

body#layout {
  background: #f8f9fa;
  padding: 15px 20px;
}

body#layout:before {
  content: 'قالب الشامل';
  display: block;
  text-align: center;
  background: #6c63ff;
  color: #fff;
  padding: 10px 30px;
  border-radius: 6px;
  margin-bottom: 20px;
  font-size: 16px;
}

body#layout .section {
  background: #fff;
  border-radius: 6px;
  border: 1px solid #eee;
  padding: 12px;
  margin: 8px 0;
}

body#layout .widget {
  background: #fafafa;
  border-radius: 4px;
  padding: 8px;
  margin: 5px 0;
}

/* تسميات الأقسام */
div#header:before { content: 'الهيدر' !important; }
div#navigation:before { content: 'القائمة' !important; }
div#ad-below-header:before { content: 'إعلان الهيدر' !important; }
div#ad-homepage-top:before { content: 'إعلان الرئيسية' !important; }
div#ad-above-content:before { content: 'إعلان المحتوى' !important; }
div#main-posts:before { content: 'المقالات' !important; }
div#ad-below-post:before { content: 'إعلان أسفل المقال' !important; }
div#sidebar-widgets:before { content: 'الجانب' !important; }
div#ad-above-footer:before { content: 'إعلان الفوتر' !important; }
div#footer:before { content: 'الفوتر' !important; }

div#header:before,
div#navigation:before,
div#ad-below-header:before,
div#ad-homepage-top:before,
div#ad-above-content:before,
div#main-posts:before,
div#ad-below-post:before,
div#sidebar-widgets:before,
div#ad-above-footer:before,
div#footer:before {
  display: block;
  background: #1a1a2e;
  color: #fff;
  padding: 6px 12px;
  border-radius: 4px;
  margin: -12px -12px 10px -12px;
  font-size: 12px;
  text-align: center;
}

/* إخفاء غير الضروري */
body#layout h4 { display: none; }

/* ترتيب المحتوى والجانب */
#main-posts, #sidebar-widgets { display: inline-block; vertical-align: top; }
#main-posts { width: 68%; }
#sidebar-widgets { width: 30%; }

#footer .section { display: inline-block; width: 32%; vertical-align: top; }

@media (max-width: 768px) {
  #main-posts, #sidebar-widgets { width: 100%; }
  #footer .section { width: 100%; margin-bottom: 10px; }
}

b:if.script:
  //
  document.addEventListener("DOMContentLoaded", function () {

    var content = document.getElementById("post-content");
    if (!content) return;

var ad1 = document.querySelector('.post-ad-middle-1');
var ad2 = document.querySelector('.post-ad-middle-2');
    if (!ad1 || !ad2) return;

    if (ad1.dataset.done) return;

    var blocks = content.querySelectorAll("p");

    if (blocks.length < 3) {
      blocks = content.querySelectorAll("br");
    }

    if (blocks.length < 4) return;

    var pos1 = Math.floor(blocks.length * 0.33);
    var pos2 = Math.floor(blocks.length * 0.66);

    if (pos1 === pos2) pos2 = pos1 + 1;
    if (pos2 >= blocks.length) pos2 = blocks.length - 1;

    blocks[pos1].parentNode.insertBefore(ad1, blocks[pos1].nextSibling);

    blocks = content.querySelectorAll("p");
    if (blocks.length < 3) blocks = content.querySelectorAll("br");

    if (blocks[pos2]) {
      blocks[pos2].parentNode.insertBefore(ad2, blocks[pos2].nextSibling);
    }

    ad1.dataset.done = "true";
    ad2.dataset.done = "true";

  });
  //

body.script:
//

/**
 * قالب بلوجر الشامل v2.0 - جميع سكريبتات القالب
 */
(function() {
  'use strict';

  /* ==========================================
     دالة التاريخ النسبي بالعربية
  ========================================== */
  function getArabicRelativeTime(isoDate) {
    var now = new Date();
    var pubDate = new Date(isoDate);
    var diffSecs = Math.floor((now - pubDate) / 1000);
    var min = 60, hour = 3600, day = 86400, week = 604800, month = 2592000, year = 31536000;

    function fmt(n, one, two, few, many) {
      if (n === 1) return 'منذ ' + one;
      if (n === 2) return 'منذ ' + two;
      if (n >= 3 && n <= 10) return 'منذ ' + n + ' ' + few;
      return 'منذ ' + n + ' ' + many;
    }

    if (diffSecs < 60)  return 'الآن';
    if (diffSecs < hour)  return fmt(Math.floor(diffSecs / min),   'دقيقة',   'دقيقتين',  'دقائق',  'دقيقة');
    if (diffSecs < day)   return fmt(Math.floor(diffSecs / hour),  'ساعة',    'ساعتين',   'ساعات',  'ساعة');
    if (diffSecs < week)  return fmt(Math.floor(diffSecs / day),   'يوماً', 'يومين',    'أيام',   'يوماً');
    if (diffSecs < month) return fmt(Math.floor(diffSecs / week),  'أسبوع',  'أسبوعين',    'أسابيع', 'أسبوع');
    if (diffSecs < year)  return fmt(Math.floor(diffSecs / month), 'شهر',    'شهرين',    'أشهر',   'شهراً');
    return fmt(Math.floor(diffSecs / year),  'سنة',    'سنتين',    'سنوات',  'سنة');
  }

  /* تحديث جميع التواريخ في الصفحة */
  function updateAllDates() {
    // تحديث تواريخ المقالات
    document.querySelectorAll('[data-date]').forEach(function(el) {
      var iso = el.getAttribute('data-date');
      if (!iso) return;
      var rel = getArabicRelativeTime(iso);
      var svg = el.querySelector('svg');
      if (svg) {
        el.innerHTML = '';
        el.appendChild(svg);
        el.appendChild(document.createTextNode(' ' + rel));
      } else {
        el.textContent = rel;
      }
    });
    
    // تحديث تواريخ التعليقات (timeAgo)
    document.querySelectorAll('.comment-date[data-timestamp]').forEach(function(el) {
      var iso = el.getAttribute('data-timestamp');
      if (!iso) return;
      var rel = getArabicRelativeTime(iso);
      // إضافة "منذ" قبل الوقت النسبي
      el.textContent = 'منذ ' + rel;
    });
  }
  window.updateAllDates = updateAllDates;

  /* ==========================================
     Reply button handler - معالجة زر الرد على التعليقات
  ========================================== */
  function initCommentReplyButtons() {
    var replyLinks = document.querySelectorAll('.comment-action.reply-link');
    
    replyLinks.forEach(function(link) {
      link.addEventListener('click', function(e) {
        e.preventDefault();
        
        // Get the parent comment ID from the href
        var href = this.querySelector('a').getAttribute('href');
        var parentIdMatch = href.match(/parentID=(\d+)/);
        
        if (parentIdMatch) {
          var parentId = parentIdMatch[1];
          
          // Try to find and click Blogger's reply iframe/button
          var commentForm = document.getElementById('comment-editor');
          if (commentForm) {
            // Scroll to comment form
            commentForm.scrollIntoView({ behavior: 'smooth', block: 'center' });
            
            // Try to set parent ID if Blogger provides a way
            var replyForm = document.querySelector('[data-reply-to]');
            if (replyForm) {
              replyForm.setAttribute('data-reply-to', parentId);
            }
            
            // Also try to find the reply form by parent ID
            var replyInputs = document.querySelectorAll('input[name="parentID"]');
            replyInputs.forEach(function(input) {
              input.value = parentId;
            });
            
            // Show a message to the user
            console.log('Reply to comment ID: ' + parentId);
          } else {
            // If no embedded form, try to open comment page
            window.location.href = href;
          }
        }
      });
    });
  }

  /* ==========================================
     شريط تقدم القراءة
  ========================================== */
  function initReadingProgress() {
    var bar = document.getElementById('reading-progress');
    if (!bar) return;
    window.addEventListener('scroll', function() {
      var scrolled = window.scrollY || document.documentElement.scrollTop;
      var total = document.documentElement.scrollHeight - window.innerHeight;
      bar.style.transform = 'scaleX(' + (total > 0 ? Math.min(scrolled / total, 1) : 0) + ')';
    }, { passive: true });
  }

  /* ==========================================
     زر قائمة Mobile
  ========================================== */
  function initLazyImages() {
    // استخدام التحميل الكسول الأصلي للمتصفحات الحديثة
    if ('loading' in HTMLImageElement.prototype) {
      // المتصفح يدعم loading=lazy
      document.querySelectorAll('img[loading="lazy"]').forEach(function(img) {
        img.src = img.dataset.src || img.src;
      });
    } else {
      // للمتصفحات القديمة - تحميل فوري
      document.querySelectorAll('img[data-src]').forEach(function(img) {
        img.src = img.dataset.src;
      });
    }
  }

  /* ==========================================
     زر قائمة Mobile
  ========================================== */
  function initMobileMenu() {
    var btn = document.getElementById('menu-toggle-btn');
    var sidebar = document.getElementById('sidebar-menu');
    var overlay = document.getElementById('sidebar-overlay');
    var closeBtn = document.getElementById('sidebar-close');
    var navSection = document.getElementById('nav-menu');
    
    if (!btn || !sidebar) return;

    function toggleSidebar() {
      var isOpen = sidebar.classList.toggle('active');
      
      if (isOpen) {
        sidebar.setAttribute('aria-hidden', 'false');
        btn.setAttribute('aria-expanded', 'true');
        btn.setAttribute('aria-label', 'إغلاق القائمة الجانبية');
        btn.classList.add('active');
        document.body.style.overflow = 'hidden';
        if (overlay) overlay.classList.add('active');
      } else {
        sidebar.setAttribute('aria-hidden', 'true');
        btn.setAttribute('aria-expanded', 'false');
        btn.setAttribute('aria-label', 'فتح قائمة التنقل');
        btn.classList.remove('active');
        document.body.style.overflow = '';
        if (overlay) overlay.classList.remove('active');
      }
    }

    // Toggle nav-section for mobile dropdown menu
    if (btn && navSection) {
      btn.addEventListener('click', function(e) {
        e.stopPropagation();
        // Toggle the mobile navigation dropdown
        navSection.classList.toggle('active');
        // Also toggle sidebar if needed
        toggleSidebar();
      });
    } else if (btn) {
      btn.addEventListener('click', function(e) {
        e.stopPropagation();
        toggleSidebar();
      });
    }

    if (closeBtn) {
      closeBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        toggleSidebar();
        if (navSection) navSection.classList.remove('active');
      });
    }

    if (overlay) {
      overlay.addEventListener('click', function(e) {
        e.stopPropagation();
        toggleSidebar();
        if (navSection) navSection.classList.remove('active');
      });
    }

    document.addEventListener('click', function(e) {
      if (!sidebar.contains(e.target) && !btn.contains(e.target) && sidebar.classList.contains('active')) {
        toggleSidebar();
      }
      // Close mobile nav when clicking outside
      if (navSection && !navSection.contains(e.target) && !btn.contains(e.target) && navSection.classList.contains('active')) {
        navSection.classList.remove('active');
      }
    });

    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape' && sidebar.classList.contains('active')) {
        toggleSidebar();
        if (navSection) navSection.classList.remove('active');
      }
    });

    sidebar.addEventListener('click', function(e) {
      e.stopPropagation();
    });
  }

  /* ==========================================
     Populate Sidebar Menu from Main Navigation
     Creates hierarchical menu with +, ++ support
  ========================================== */
  
  // Global variable to store original menu HTML for sidebar
  var originalMenuHTML = '';
  
  function populateSidebarMenu() {
    var sidebarNav = document.getElementById('sidebar-nav');
    
    if (!sidebarNav) return;
    
    // Get the main navigation - use the modified version after convertMenuToDropdown
    var mainNav = document.getElementById('main-navigation');
    if (!mainNav) {
      mainNav = document.getElementById('navbar');
    }
    if (!mainNav) {
      mainNav = document.querySelector('.main-nav');
    }
    
    // Build HTML starting with home link
    var html = '<li role="none"><a href="/" role="menuitem"><span class="menu-icon"><svg aria-hidden="true" fill="none" focusable="false" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg></span>الرئيسية</a></li>';
    
    // If mainNav exists and has items, populate from it
    if (mainNav) {
      var mainNavItems = mainNav.querySelectorAll(':scope > li');
      
      mainNavItems.forEach(function(item) {
        var link = item.querySelector('a');
        if (link) {
          // Get text content - remove any + or ++ prefixes
          var linkText = link.textContent || '';
          linkText = linkText.replace(/^\+\+/, '').replace(/^\+/, '').trim();
          var linkHref = link.getAttribute('href') || '#';
          
          // Skip if href is just # or https:// or empty
          if (linkHref === '#' || linkHref === 'https://' || linkText.trim() === '') {
            return;
          }
          
          // Check if this is a dropdown item (has sub-menu)
          var hasSubMenu = item.querySelector(':scope > .sub-menu') !== null;
          
          if (hasSubMenu) {
            // Has sub-menu - create expandable item
            html += '<li role="none" class="sidebar-has-submenu">';
            html += '<div class="menu-item-wrapper">';
            html += '<a href="' + linkHref + '" class="sidebar-menu-link" role="menuitem">' + linkText + '</a>';
            html += '<button class="sidebar-submenu-toggle" aria-label="فتح القائمة الفرعية"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="9 18 15 12 9 6"></polyline></svg></button>';
            html += '</div>';
            html += '<ul class="sidebar-submenu">';
            
            // Get sub-items
            var subMenu = item.querySelector('.sub-menu');
            if (subMenu) {
              var subMenuItems = subMenu.querySelectorAll('li');
              subMenuItems.forEach(function(subItem) {
                var subLink = subItem.querySelector('a');
                if (subLink) {
                  var subHref = subLink.getAttribute('href') || '#';
                  var subText = subLink.textContent || '';
                  subText = subText.replace(/^\+\+/, '').replace(/^\+/, '').trim();
                  
                  if (subHref === '#' || subHref === 'https://' || subText.trim() === '') {
                    return;
                  }
                  
                  var subHasNested = subItem.querySelector('.sub-menu') !== null;
                  
                  if (subHasNested) {
                    html += '<li role="none" class="sidebar-has-submenu">';
                    html += '<div class="menu-item-wrapper">';
                    html += '<a href="' + subHref + '" class="sidebar-menu-link" role="menuitem">' + subText + '</a>';
                    html += '<button class="sidebar-submenu-toggle" aria-label="فتح القائمة الفرعية"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="9 18 15 12 9 6"></polyline></svg></button>';
                    html += '</div>';
                    html += '<ul class="sidebar-submenu">';
                    
                    var nestedSubMenu = subItem.querySelector('.sub-menu');
                    if (nestedSubMenu) {
                      var nestedItems = nestedSubMenu.querySelectorAll('li');
                      nestedItems.forEach(function(nestedItem) {
                        var nestedLink = nestedItem.querySelector('a');
                        if (nestedLink) {
                          var nestedHref = nestedLink.getAttribute('href') || '#';
                          var nestedText = nestedLink.textContent || '';
                          nestedText = nestedText.replace(/^\+\+/, '').replace(/^\+/, '').trim();
                          
                          if (nestedHref !== '#' && nestedHref !== 'https://' && nestedText.trim() !== '') {
                            html += '<li role="none"><a href="' + nestedHref + '" role="menuitem">' + nestedText + '</a></li>';
                          }
                        }
                      });
                    }
                    
                    html += '</ul></li>';
                  } else {
                    html += '<li role="none"><a href="' + subHref + '" role="menuitem">' + subText + '</a></li>';
                  }
                }
              });
            }
            
            html += '</ul></li>';
          } else {
            // Regular menu item
            html += '<li role="none"><a href="' + linkHref + '" role="menuitem">' + linkText + '</a></li>';
          }
        }
      });
    }
    
    // Set the HTML
    sidebarNav.innerHTML = html;
    
    // Add toggle functionality
    initSidebarSubmenus();
  }
  
  /* ==========================================
     Initialize Sidebar Submenu Toggles
  ========================================== */
  function initSidebarSubmenus() {
    // دالة مشتركة لتبديل القائمة الفرعية
    function toggleSubmenu(parent) {
      var submenu = parent.querySelector('.sidebar-submenu');
      var toggle = parent.querySelector('.sidebar-submenu-toggle');
      
      if (submenu) {
        // إغلاق القوائم الشقيقة أولاً
        var siblings = parent.parentElement.querySelectorAll(':scope > .sidebar-has-submenu.active');
        siblings.forEach(function(sibling) {
          if (sibling !== parent) {
            var siblingSubmenu = sibling.querySelector('.sidebar-submenu');
            var siblingToggle = sibling.querySelector('.sidebar-submenu-toggle');
            if (siblingSubmenu) siblingSubmenu.classList.remove('active');
            if (siblingToggle) siblingToggle.classList.remove('active');
          }
        });
        
        // تبديل القائمة الحالية
        var isActive = submenu.classList.toggle('active');
        if (toggle) {
          toggle.classList.toggle('active');
          // تحديث دوران السهم
          var svg = toggle.querySelector('svg');
          if (svg) {
            svg.style.transform = isActive ? 'rotate(270deg)' : 'rotate(180deg)';
          }
        }
      }
    }
    
    // إضافة حدث النقر لزر السهم
    var toggles = document.querySelectorAll('.sidebar-submenu-toggle');
    
    toggles.forEach(function(toggle) {
      toggle.addEventListener('click', function(e) {
        e.preventDefault();
        e.stopPropagation();
        
        var parent = toggle.closest('.sidebar-has-submenu');
        toggleSubmenu(parent);
      });
    });
    
    // إضافة حدث النقر للرابط لفتح القائمة الفرعية
    var menuLinks = document.querySelectorAll('.sidebar-has-submenu > .menu-item-wrapper > .sidebar-menu-link');
    
    menuLinks.forEach(function(link) {
      link.addEventListener('click', function(e) {
        // إذا كان هناك قائمة فرعية، افتحها بدلاً من الانتقال للرابط
        var parent = link.closest('.sidebar-has-submenu');
        var submenu = parent.querySelector('.sidebar-submenu');
        
        if (submenu) {
          e.preventDefault();
          toggleSubmenu(parent);
        }
      });
    });
  }
  
  function convertMenuToDropdown() {
    // Find navigation element - try multiple selectors
    var nav = document.getElementById('main-navigation');
    if (!nav) {
      nav = document.getElementById('navbar');
    }
    if (!nav) {
      nav = document.querySelector('.main-nav');
    }
    if (!nav) return;
    
    // Store original HTML before modifying
    originalMenuHTML = nav.innerHTML;
    
    var items = nav.querySelectorAll('li');
    var links = [];
    
    // Collect all links with their info
    items.forEach(function(item) {
      var link = item.querySelector('a');
      if (link) {
        links.push({
          element: item,
          name: link.getAttribute('title') || link.textContent,
          href: link.getAttribute('href'),
          target: link.getAttribute('target')
        });
      }
    });
    
    // Clear the navigation
    nav.innerHTML = '';
    
    // Build menu structure with nested sub-items
    var menuStructure = [];
    var currentMainItem = null;
    var currentSubItem = null;
    
    for (var i = 0; i < links.length; i++) {
      var current = links[i];
      var name = current.name;
      
      // Check for ++ prefix (secondary sub-item)
      if (name.indexOf('++') === 0) {
        var displayName = name.replace(/^\+\+/, '').trim();
        
        // Add to current sub-item's nested menu
        if (currentSubItem) {
          currentSubItem.nestedItems.push({
            name: displayName,
            href: current.href
          });
        } else if (currentMainItem) {
          // No parent sub-item, add to main item's sub-menu
          currentMainItem.subItems.push({
            name: displayName,
            href: current.href,
            nestedItems: []
          });
        }
        continue;
      }
      
      // Check for + prefix (sub-menu item)
      if (name.indexOf('+') === 0) {
        var displayName = name.replace(/^\+/, '').trim();
        
        // Add to current main item's sub-menu
        if (currentMainItem) {
          currentMainItem.subItems.push({
            name: displayName,
            href: current.href,
            nestedItems: []
          });
          // Track current sub-item for ++ nesting
          currentSubItem = currentMainItem.subItems[currentMainItem.subItems.length - 1];
        }
        continue;
      }
      
      // This is a main menu item (no prefix)
      currentMainItem = {
        name: name,
        href: current.href,
        subItems: []
      };
      currentSubItem = null; // Reset for new main item
      menuStructure.push(currentMainItem);
    }
    
    // Build HTML from structure
    for (var j = 0; j < menuStructure.length; j++) {
      var item = menuStructure[j];
      
      if (item.subItems.length > 0) {
        // Has sub-items - create dropdown
        var li = document.createElement('li');
        li.className = 'sitem';
        
        var html = '<a class="dropdown-arrow" href="' + item.href + '" title="' + item.name + '">' + item.name + '</a>';
        html += '<ul class="sub-menu">';
        
        for (var k = 0; k < item.subItems.length; k++) {
          var subItem = item.subItems[k];
          
          if (subItem.nestedItems && subItem.nestedItems.length > 0) {
            // Has nested items - create nested dropdown
            html += '<li class="sitem">';
            html += '<a class="dropdown-arrow" href="' + subItem.href + '">' + subItem.name + '</a>';
            html += '<ul class="sub-menu">';
            
            for (var n = 0; n < subItem.nestedItems.length; n++) {
              html += '<li class="ssitem"><a href="' + subItem.nestedItems[n].href + '">' + subItem.nestedItems[n].name + '</a></li>';
            }
            
            html += '</ul></li>';
          } else {
            // Simple sub-item
            html += '<li class="ssitem"><a href="' + subItem.href + '">' + subItem.name + '</a></li>';
          }
        }
        
        html += '</ul>';
        li.innerHTML = html;
        nav.appendChild(li);
      } else {
        // No sub-items - regular menu item
        var liItem = document.createElement('li');
        liItem.className = 'item';
        liItem.innerHTML = '<a href="' + item.href + '" title="' + item.name + '">' + item.name + '</a>';
        nav.appendChild(liItem);
      }
    }
    
    // Initialize mobile dropdown after conversion
    if (typeof initMobileDropdown === 'function') {
      initMobileDropdown();
    }
  }

  /* ==========================================
     Mobile Dropdown Sub-Menu Toggle (Click to expand)
     Supports nested sub-menus (++ items)
  ========================================== */
  function initMobileDropdown() {
    // Only run on mobile (width <= 768px)
    if (window.innerWidth > 768) return;
    
    // Handle first level dropdowns (items with + prefix)
    var dropdownItems = document.querySelectorAll('.main-nav li.sitem');
    
    dropdownItems.forEach(function(item) {
      var link = item.querySelector('a.dropdown-arrow');
      var submenu = item.querySelector('.sub-menu');
      
      if (link && submenu) {
        // Remove existing listeners to avoid duplicates
        var newLink = link.cloneNode(true);
        link.parentNode.replaceChild(newLink, link);
        
        newLink.addEventListener('click', function(e) {
          e.preventDefault();
          e.stopPropagation();
          
          // Toggle the sub-menu
          submenu.classList.toggle('active');
          newLink.classList.toggle('active');
          
          // Close other sub-menus at same level
          dropdownItems.forEach(function(otherItem) {
            if (otherItem !== item) {
              var otherSubmenu = otherItem.querySelector('.sub-menu');
              var otherLink = otherItem.querySelector('a.dropdown-arrow');
              if (otherSubmenu) otherSubmenu.classList.remove('active');
              if (otherLink) otherLink.classList.remove('active');
            }
          });
        });
      }
    });
    
    // Handle nested dropdowns (second level - items with ++ prefix)
    var nestedItems = document.querySelectorAll('.main-nav .sub-menu li.sitem');
    
    nestedItems.forEach(function(item) {
      var link = item.querySelector('a.dropdown-arrow');
      var nestedSubmenu = item.querySelector('.sub-menu');
      
      if (link && nestedSubmenu) {
        // Remove existing listeners to avoid duplicates
        var newLink = link.cloneNode(true);
        link.parentNode.replaceChild(newLink, link);
        
        newLink.addEventListener('click', function(e) {
          e.preventDefault();
          e.stopPropagation();
          
          // Toggle the nested sub-menu
          nestedSubmenu.classList.toggle('active');
          newLink.classList.toggle('active');
          
          // Close other nested sub-menus
          nestedItems.forEach(function(otherItem) {
            if (otherItem !== item) {
              var otherNested = otherItem.querySelector('.sub-menu');
              var otherLink = otherItem.querySelector('a.dropdown-arrow');
              if (otherNested) otherNested.classList.remove('active');
              if (otherLink) otherLink.classList.remove('active');
            }
          });
        });
      }
    });
  }

  /* ==========================================
     Mobile dropdown toggle - Initialize on load and resize
  ========================================== */
  function initMobileDropdownToggle() {
    initMobileDropdown();
    
    // Re-initialize on window resize
    window.addEventListener('resize', function() {
      initMobileDropdown();
    });
  }

  /* ==========================================
     تأثير Scroll Reveal للبطاقات
  ========================================== */
  function initScrollReveal() {
    if (!('IntersectionObserver' in window)) return;
    var cards = document.querySelectorAll('.post-card, .timeline-post-item, .related-post-item');
    var observer = new IntersectionObserver(function(entries) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          entry.target.style.opacity = '1';
          entry.target.style.transform = 'translateY(0)';
          observer.unobserve(entry.target);
        }
      });
    }, { threshold: 0.1 });
    cards.forEach(function(card) { observer.observe(card); });
  }

  /* ==========================================
     إدارة Pagination - تحميل المزيد
  ========================================== */
  var paginationState = {
    isLoading: false,
    hasMore: true,
    startIndex: 7,
    maxResults: 6,
    blogId: null,
    totalPosts: 0,
    loadedCount: 0,
    currentLabel: null,
    currentYear: null,
    currentMonth: null,
    // Date filter parameters from URL query string
    updatedMax: null,
    updatedMin: null,
    urlMaxResults: null
  };
  
  // Get current label from page URL or elements
  function getCurrentLabel() {
    var label = null;
    
    // Method 1: From URL
    var pathname = window.location.pathname;
    var labelMatch = pathname.match(/\/search\/label\/([^/?#]+)/);
    if (labelMatch) {
      label = decodeURIComponent(labelMatch[1]);
      return label;
    }
    
    // Method 2: From page elements
    var labelElements = document.querySelectorAll('.post-label, .post-label-bottom, .label-link');
    for (var i = 0; i < labelElements.length; i++) {
      var text = labelElements[i].textContent.trim();
      if (text && text !== 'الرئيسية' && text !== 'Home') {
        label = text;
        break;
      }
    }
    
    return label;
  }
  
  // Get current archive date from URL (e.g., /2026/ or /2026/01/)
  function getCurrentArchiveDate() {
    var pathname = window.location.pathname;
    var year = null;
    var month = null;
    
    // Match /YYYY/ or /YYYY/MM/ pattern
    var archiveMatch = pathname.match(/\/(\d{4})\/(\d{2})?\/?$/);
    if (archiveMatch) {
      year = archiveMatch[1];
      month = archiveMatch[2] || null;
      return { year: year, month: month };
    }
    
    // Also check for /YYYY_MM_dd_archive.html pattern
    var archiveHtmlMatch = pathname.match(/\/(\d{4})_(\d{2})_(\d{2})_archive\.html$/);
    if (archiveHtmlMatch) {
      year = archiveHtmlMatch[1];
      month = archiveHtmlMatch[2];
      return { year: year, month: month };
    }
    
    return { year: null, month: null };
  }
  
  // Get date filter parameters from URL query string (e.g., updated-max, updated-min)
  function getDateFilterParams() {
    var params = {
      updatedMax: null,
      updatedMin: null,
      maxResults: null
    };
    
    var urlParams = new URLSearchParams(window.location.search);
    
    // Check for updated-max parameter
    if (urlParams.has('updated-max')) {
      params.updatedMax = urlParams.get('updated-max');
    }
    
    // Check for updated-min parameter
    if (urlParams.has('updated-min')) {
      params.updatedMin = urlParams.get('updated-min');
    }
    
    // Check for max-results parameter
    if (urlParams.has('max-results')) {
      params.maxResults = parseInt(urlParams.get('max-results'), 10);
    }
    
    // Also check for published-max and published-min (alternative parameter names)
    if (urlParams.has('published-max') && !params.updatedMax) {
      params.updatedMax = urlParams.get('published-max');
    }
    
    if (urlParams.has('published-min') && !params.updatedMin) {
      params.updatedMin = urlParams.get('published-min');
    }
    
    return params;
  }
  
  // Check if current page has date filter parameters
  function hasDateFilter() {
    var urlParams = new URLSearchParams(window.location.search);
    return urlParams.has('updated-max') || urlParams.has('updated-min') || 
           urlParams.has('published-max') || urlParams.has('published-min');
  }
  
  // Initialize Pagination - Get Blog ID from Feed link
  function initFeedPagination() {
    var blogPostsContainer = document.querySelector('.blog-posts');
    var loadMoreBtn = document.getElementById('load-more-btn');
    if (!blogPostsContainer) return;
    
    // Hide load more button initially on date-filtered pages
    // We'll show it later if there are more posts to load
    if (hasDateFilter() && loadMoreBtn) {
      loadMoreBtn.style.display = 'none';
    }
    
    // Count existing posts
    var existingPosts = blogPostsContainer.querySelectorAll('.post-card');
    paginationState.loadedCount = existingPosts.length;
    
    // Hide pagination button if loaded posts <= max-results (no more pages)
    // This applies to all pages, not just date-filtered ones
    if (loadMoreBtn && paginationState.loadedCount > 0 && paginationState.loadedCount <= paginationState.maxResults) {
      loadMoreBtn.style.display = 'none';
      paginationState.hasMore = false;
    }
    
    // Get current label if on label page
    paginationState.currentLabel = getCurrentLabel();
    
    // Get current archive date if on archive page
    var archiveDate = getCurrentArchiveDate();
    paginationState.currentYear = archiveDate.year;
    paginationState.currentMonth = archiveDate.month;
    
    // Get date filter parameters from URL query string
    var dateFilterParams = getDateFilterParams();
    paginationState.updatedMax = dateFilterParams.updatedMax;
    paginationState.updatedMin = dateFilterParams.updatedMin;
    if (dateFilterParams.maxResults) {
      paginationState.maxResults = dateFilterParams.maxResults;
    }
    
    // Get Blog ID from Feed link
    var feedLinks = document.querySelectorAll('link[rel="alternate"]');
    for (var i = 0; i < feedLinks.length; i++) {
      var href = feedLinks[i].getAttribute('href') || '';
      var match = href.match(/\/feeds\/(\d+)\//);
      if (match) {
        paginationState.blogId = match[1];
        break;
      }
    }
    
    // Get Blog ID from page data - هذا الخيار الأكثر موثوقية
    var pageData = document.querySelector('*[data-blog-id]');
    if (pageData) {
      paginationState.blogId = pageData.getAttribute('data-blog-id');
    } else {
      // Fallback: Try to get from Blogger data
      var blogIdElement = document.querySelector('[data-id]');
      if (blogIdElement) {
        var match = blogIdElement.getAttribute('data-id').match(/blog-(\d+)/);
        if (match) {
          paginationState.blogId = match[1];
        }
      }
    }

    // If still not found, show error instead of using wrong ID
    if (!paginationState.blogId) {
      console.error('Error: Could not determine Blog ID. Please check your template.');
      return;
    }
    
    // Set start-index based on existing posts
    if (paginationState.loadedCount > 0) {
      paginationState.startIndex = paginationState.loadedCount + 1;
    }
    
    // Check if there are more posts on label pages or archive pages or date-filtered pages
    if (paginationState.currentLabel && paginationState.loadedCount > 0) {
      checkLabelPostCount();
    } else if (paginationState.currentYear && paginationState.loadedCount > 0) {
      // Check archive post count
      checkArchivePostCount();
    } else if ((paginationState.updatedMax || paginationState.updatedMin) && paginationState.loadedCount > 0) {
      // Check post count for date-filtered search pages
      checkDateFilteredPostCount();
    } else if ((paginationState.updatedMax || paginationState.updatedMin) && paginationState.loadedCount === 0) {
      // Check post count for date-filtered pages with no initial posts
      checkDateFilteredPostCount();
    } else if (!paginationState.currentLabel && !paginationState.currentYear && !hasDateFilter() && loadMoreBtn) {
      // Show Load More on regular pages (not labels, not archives, not date-filtered)
      loadMoreBtn.style.display = 'inline-flex';
    } else if (paginationState.currentYear && loadMoreBtn) {
      // Show Load More on archive pages
      loadMoreBtn.style.display = 'inline-flex';
    } else if (loadMoreBtn && !hasDateFilter()) {
      // Default: show Load More if no date filter
      loadMoreBtn.style.display = 'inline-flex';
    }
  }
  
  // Check total post count for label pages
  function checkLabelPostCount() {
    var feedUrl = 'https://www.blogger.com/feeds/' + paginationState.blogId + '/posts/summary/-/' + encodeURIComponent(paginationState.currentLabel);
    var url = feedUrl + '?alt=json-in-script&max-results=1&callback=handleLabelCount';
    
    window.handleLabelCount = function(data) {
      var loadMoreBtn = document.getElementById('load-more-btn');
      var endEl = document.getElementById('pagination-end');
      
      if (data && data.feed && data.feed.openSearch$totalResults) {
        var totalPosts = parseInt(data.feed.openSearch$totalResults.$t) || 0;
        paginationState.totalPosts = totalPosts;
        
        if (paginationState.loadedCount >= totalPosts) {
          paginationState.hasMore = false;
          if (loadMoreBtn) loadMoreBtn.style.display = 'none';
          if (endEl) endEl.style.display = 'block';
        } else {
          if (loadMoreBtn) loadMoreBtn.style.display = 'inline-flex';
        }
      } else {
        if (loadMoreBtn) loadMoreBtn.style.display = 'inline-flex';
      }
      
      delete window.handleLabelCount;
    };
    
    var script = document.createElement('script');
    script.src = url;
    script.charset = 'utf-8';
    document.getElementsByTagName('head')[0].appendChild(script);
  }
  
  // Check total post count for archive pages
  function checkArchivePostCount() {
    if (!paginationState.currentYear) return;
    
    var minDate, maxDate;
    if (paginationState.currentMonth) {
      var year = parseInt(paginationState.currentYear);
      var month = parseInt(paginationState.currentMonth);
      minDate = year + '-' + String(month).padStart(2, '0') + '-01T00:00:00';
      var nextMonth = month === 12 ? 1 : month + 1;
      var nextYear = month === 12 ? year + 1 : year;
      maxDate = nextYear + '-' + String(nextMonth).padStart(2, '0') + '-01T00:00:00';
    } else {
      minDate = paginationState.currentYear + '-01-01T00:00:00';
      maxDate = (parseInt(paginationState.currentYear) + 1) + '-01-01T00:00:00';
    }
    
    var feedUrl = 'https://www.blogger.com/feeds/' + paginationState.blogId + '/posts/summary';
    var url = feedUrl + '?alt=json-in-script&max-results=1&published-min=' + encodeURIComponent(minDate) + '&published-max=' + encodeURIComponent(maxDate) + '&callback=handleArchiveCount';
    
    window.handleArchiveCount = function(data) {
      var loadMoreBtn = document.getElementById('load-more-btn');
      var endEl = document.getElementById('pagination-end');
      
      if (data && data.feed && data.feed.openSearch$totalResults) {
        var totalPosts = parseInt(data.feed.openSearch$totalResults.$t) || 0;
        paginationState.totalPosts = totalPosts;
        
        if (paginationState.loadedCount >= totalPosts) {
          paginationState.hasMore = false;
          if (loadMoreBtn) loadMoreBtn.style.display = 'none';
          if (endEl) endEl.style.display = 'block';
        } else {
          if (loadMoreBtn) loadMoreBtn.style.display = 'inline-flex';
        }
      } else {
        if (loadMoreBtn) loadMoreBtn.style.display = 'inline-flex';
      }
      
      delete window.handleArchiveCount;
    };
    
    var script = document.createElement('script');
    script.src = url;
    script.charset = 'utf-8';
    document.getElementsByTagName('head')[0].appendChild(script);
  }

  // Check total post count for date-filtered search pages
  function checkDateFilteredPostCount() {
    var feedUrl = 'https://www.blogger.com/feeds/' + paginationState.blogId + '/posts/summary';
    
    // Add label path if on label page
    if (paginationState.currentLabel) {
      feedUrl = 'https://www.blogger.com/feeds/' + paginationState.blogId + '/posts/summary/-/' + encodeURIComponent(paginationState.currentLabel);
    }
    
    var url = feedUrl + '?alt=json-in-script&max-results=1';
    
    // Add date filter parameters
    // IMPORTANT: Use updated-max/min for last modified date, not published-max/min
    if (paginationState.updatedMax) {
      url += '&updated-max=' + encodeURIComponent(paginationState.updatedMax);
    }
    if (paginationState.updatedMin) {
      url += '&updated-min=' + encodeURIComponent(paginationState.updatedMin);
    }
    
    url += '&callback=handleDateFilteredCount';
    
    window.handleDateFilteredCount = function(data) {
      var loadMoreBtn = document.getElementById('load-more-btn');
      var endEl = document.getElementById('pagination-end');
      
      if (data && data.feed && data.feed.openSearch$totalResults) {
        var totalPosts = parseInt(data.feed.openSearch$totalResults.$t) || 0;
        paginationState.totalPosts = totalPosts;
        
        if (paginationState.loadedCount >= totalPosts) {
          paginationState.hasMore = false;
          if (loadMoreBtn) loadMoreBtn.style.display = 'none';
          if (endEl) endEl.style.display = 'block';
        } else {
          if (loadMoreBtn) loadMoreBtn.style.display = 'inline-flex';
        }
      } else {
        if (loadMoreBtn) loadMoreBtn.style.display = 'inline-flex';
      }
      
      delete window.handleDateFilteredCount;
    };
    
    var script = document.createElement('script');
    script.src = url;
    script.charset = 'utf-8';
    document.getElementsByTagName('head')[0].appendChild(script);
  }

  // Load More function using JSONP
  window.loadMorePosts = function() {
    if (paginationState.isLoading || !paginationState.hasMore) return;
    
    var loadMoreBtn = document.getElementById('load-more-btn');
    var blogPostsContainer = document.querySelector('.blog-posts');
    var loadingEl = document.getElementById('pagination-loading');
    var endEl = document.getElementById('pagination-end');
    
    if (!loadMoreBtn || !blogPostsContainer) {
      console.error('Required elements not found');
      return;
    }
    
    // Initialize blog ID if not set
    if (!paginationState.blogId) {
      initFeedPagination();
    }
    
    paginationState.isLoading = true;
    loadMoreBtn.style.display = 'none';
    if (loadingEl) loadingEl.style.display = 'flex';
    
    // Build Feed API URL
    // Parameters:
    // alt=json-in-script: JSONP format
    // max-results: number of posts per request
    // start-index: starting position for results
    var feedUrl = 'https://www.blogger.com/feeds/' + paginationState.blogId + '/posts/summary';
    
    // Add label path if on label page
    if (paginationState.currentLabel) {
      feedUrl = 'https://www.blogger.com/feeds/' + paginationState.blogId + '/posts/summary/-/' + encodeURIComponent(paginationState.currentLabel);
    }
    
    // Add date filter if on archive page (YYYY or YYYY/MM)
    if (paginationState.currentYear) {
      var dateQuery = paginationState.currentYear;
      if (paginationState.currentMonth) {
        dateQuery = paginationState.currentYear + '-' + paginationState.currentMonth;
      }
      // For archive pages, we need to use published date filter
      feedUrl = 'https://www.blogger.com/feeds/' + paginationState.blogId + '/posts/summary';
    }
    
    var params = {
      'alt': 'json-in-script',
      'max-results': paginationState.maxResults,
      'start-index': paginationState.startIndex,
      'callback': 'handleFeedResponse'
    };
    
    // Add date filter for archive pages
    if (paginationState.currentYear) {
      var minDate, maxDate;
      if (paginationState.currentMonth) {
        // Month archive (e.g., January 2026)
        var year = parseInt(paginationState.currentYear);
        var month = parseInt(paginationState.currentMonth);
        
        // Start of month
        minDate = year + '-' + String(month).padStart(2, '0') + '-01T00:00:00';
        
        // End of month
        var nextMonth = month === 12 ? 1 : month + 1;
        var nextYear = month === 12 ? year + 1 : year;
        maxDate = nextYear + '-' + String(nextMonth).padStart(2, '0') + '-01T00:00:00';
      } else {
        // Year archive (e.g., 2026)
        minDate = paginationState.currentYear + '-01-01T00:00:00';
        maxDate = (parseInt(paginationState.currentYear) + 1) + '-01-01T00:00:00';
      }
      
      params['published-min'] = minDate;
      params['published-max'] = maxDate;
    }
    
    // Add date filter from URL parameters (updated-max, updated-min)
    // IMPORTANT: Use updated-max/min for last modified date, not published-max/min
    if (paginationState.updatedMax) {
      params['updated-max'] = paginationState.updatedMax;
    }
    if (paginationState.updatedMin) {
      params['updated-min'] = paginationState.updatedMin;
    }
    
    // Build URL with parameters
    var url = feedUrl + '?';
    var paramArray = [];
    for (var key in params) {
      paramArray.push(key + '=' + encodeURIComponent(params[key]));
    }
    url += paramArray.join('&');
    
    // جاري التحميل...
    
    // Create JSONP script element
    var script = document.createElement('script');
    script.type = 'text/javascript';
    script.src = url;
    script.charset = 'utf-8';
    
    // Handle response
    window.handleFeedResponse = function(data) {
      try {
        processFeedData(data);
      } catch (e) {

        handleLoadError();
      }
      
      // Cleanup
      delete window.handleFeedResponse;
      if (script.parentNode) {
        script.parentNode.removeChild(script);
      }
    };
    
    // Handle errors
    script.onerror = function() {

      handleLoadError();
      delete window.handleFeedResponse;
      if (script.parentNode) {
        script.parentNode.removeChild(script);
      }
    };
    
    // Add to page
    document.getElementsByTagName('head')[0].appendChild(script);
    
    // Timeout control
    setTimeout(function() {
      if (paginationState.isLoading) {

        handleLoadError();
      }
    }, 15000);
  };
  
  // Process Feed API response
  function processFeedData(data) {
    var blogPostsContainer = document.querySelector('.blog-posts');
    var loadMoreBtn = document.getElementById('load-more-btn');
    var loadingEl = document.getElementById('pagination-loading');
    var endEl = document.getElementById('pagination-end');
    
    if (!data || !data.feed || !data.feed.entry) {
      paginationState.hasMore = false;
      paginationState.isLoading = false;
      
      if (loadingEl) loadingEl.style.display = 'none';
      if (endEl) endEl.style.display = 'block';
      

      return;
    }
    
    var entries = data.feed.entry;
    var totalResults = parseInt(data.feed.openSearch$totalResults.$t) || 0;
    

    
    paginationState.totalPosts = totalResults;
    
    // Check if there are more posts
    if (paginationState.startIndex + entries.length >= totalResults) {
      paginationState.hasMore = false;
    }
    
    // Get existing URLs to avoid duplicates
    var existingUrls = [];
    var existingPosts = blogPostsContainer.querySelectorAll('.post-card');
    existingPosts.forEach(function(post) {
      var link = post.querySelector('.post-title a');
      if (link) existingUrls.push(link.href);
    });
    
    // Create post elements
    var newPostsCount = 0;
    entries.forEach(function(entry) {
      // Check if post already exists
      var postUrl = '';
      if (entry.link) {
        entry.link.forEach(function(link) {
          if (link.rel === 'alternate') {
            postUrl = link.href;
          }
        });
      }
      
      if (!postUrl || existingUrls.indexOf(postUrl) !== -1) {
        return; // Skip duplicates
      }
      
      existingUrls.push(postUrl);
      
      // Extract data
      var title = entry.title ? entry.title.$t : 'بدون عنوان';
      var summary = '';
      if (entry.summary) {
        summary = entry.summary.$t;
      } else if (entry.content) {
        summary = entry.content.$t;
      }
      
      // Clean summary (remove HTML)
      summary = summary.replace(/<[^>]*>/g, '').substring(0, 150);
      if (summary.length >= 150) summary += '...';
      
      var date = '';
      var dateIso = '';
      if (entry.published) {
        dateIso = entry.published.$t;
        date = formatDate(dateIso);
      }
      
      // Extract image
      var imageUrl = '';
      if (entry.media$thumbnail) {
        imageUrl = entry.media$thumbnail.url;
      } else if (entry.content && entry.content.$t) {
        var imgMatch = entry.content.$t.match(/<img[^>]+src=["']([^"']+)["']/);
        if (imgMatch) imageUrl = imgMatch[1];
      }
      
      // Extract category
      var category = '';
      if (entry.category) {
        category = entry.category[0].term || '';
      }
      
      // Extract author
      var authorName = '';
      if (entry.author && entry.author[0]) {
        authorName = entry.author[0].name.$t || '';
      }
      
      // Create post element
      var postHtml = createPostCard({
        title: title,
        url: postUrl,
        summary: summary,
        date: date,
        dateIso: dateIso,
        image: imageUrl,
        category: category,
        author: authorName
      });
      
      // Add to container
      var tempDiv = document.createElement('div');
      tempDiv.innerHTML = postHtml;
      var postCard = tempDiv.firstElementChild;
      
      if (postCard) {
        blogPostsContainer.appendChild(postCard);
        newPostsCount++;
      }
    });
    
    // Update index
    paginationState.startIndex += entries.length;
    paginationState.loadedCount += newPostsCount;
    
    // Hide loading and show button or end message
    if (loadingEl) loadingEl.style.display = 'none';
    
    if (paginationState.hasMore && newPostsCount > 0) {
      loadMoreBtn.style.display = 'inline-flex';
      window.scrollTo({ top: window.scrollY + 100, behavior: 'smooth' });
    } else {
      paginationState.hasMore = false;
      if (endEl) endEl.style.display = 'block';
    }
    
    paginationState.isLoading = false;
    

  }
  
  // Create post card HTML
  function createPostCard(postData) {
    var imageHtml = '';
    var categoryHtml = '';
    
    if (postData.image) {
      imageHtml = '<a class="post-thumbnail-link" href="' + postData.url + '">' +
                  '<div class="snippet-thumbnail lazy-image wide">' +
                  '<img src="' + postData.image + '" alt="' + postData.title + '" loading="lazy"/>' +
                  '</div></a>';
    } else {
      imageHtml = '<a class="post-thumbnail-link" href="' + postData.url + '">' +
                  '<div class="snippet-thumbnail post-no-image">' +
                  '<div class="post-placeholder-image">' +
                  '<svg viewBox="0 0 24 24"><path d="M21 19V5c0-1.1-.9-2-2-2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2zM8.5 13.5l2.5 3.01L14.5 12l4.5 6H5l3.5-4.5z"/></svg>' +
                  '</div></div></a>';
    }
    
    if (postData.category) {
      categoryHtml = '<span class="post-category">' + postData.category + '</span>';
    }
    
    var html = '<article class="post-card">' +
               imageHtml +
               '<div class="post-content">' +
               '<h2 class="post-title"><a href="' + postData.url + '">' + postData.title + '</a></h2>' +
               '<p class="post-excerpt">' + postData.summary + '</p>' +
               '<div class="post-meta">' +
               '<span class="post-meta-item post-date" data-date="' + postData.dateIso + '">' +
               '<svg viewBox="0 0 24 24"><path d="M19 4h-1V2h-2v2H8V2H6v2H5c-1.11 0-1.99.9-1.99 2L3 20c0 1.1.89 2 2 2h14c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 16H5V9h14v11zM9 11H7v2h2v-2zm4 0h-2v2h2v-2zm4 0h-2v2h2v-2z"/></svg>' +
               '<span class="date-text">' + postData.date + '</span></span>' +
               '</div>' +
               '<a class="read-more" href="' + postData.url + '">قراءة المزيد</a>' +
               '</div></article>';
    
    return html;
  }
  
  // Format date to Arabic format
  function formatDate(isoDate) {
    if (!isoDate) return '';
    
    try {
      var date = new Date(isoDate);
      var months = ['يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو', 'يوليو', 'أغسطس', 'سبتمبر', 'أكتوبر', 'نوفمبر', 'ديسمبر'];
      var day = date.getDate();
      var month = months[date.getMonth()];
      var year = date.getFullYear();
      return day + ' ' + month + ' ' + year;
    } catch (e) {
      return isoDate;
    }
  }
  
  // Handle load errors
  function handleLoadError() {
    var loadMoreBtn = document.getElementById('load-more-btn');
    var loadingEl = document.getElementById('pagination-loading');
    
    paginationState.isLoading = false;
    
    if (loadingEl) loadingEl.style.display = 'none';
    if (loadMoreBtn) loadMoreBtn.style.display = 'inline-flex';
    
    // عرض رسالة خطأ styled بدلاً من alert
    var errorMsg = document.getElementById('pagination-error');
    if (!errorMsg) {
      errorMsg = document.createElement('p');
      errorMsg.id = 'pagination-error';
      errorMsg.style.cssText = 'color:#e94560;text-align:center;padding:10px;font-size:14px;';
      var container = document.getElementById('pagination-container');
      if (container) container.appendChild(errorMsg);
    }
    errorMsg.textContent = 'عذراً، حدث خطأ أثناء تحميل المقالات. يرجى المحاولة مرة أخرى.';
    setTimeout(function() { if (errorMsg) errorMsg.textContent = ''; }, 5000);
  }
  
  // Initialize on page load
  document.addEventListener('DOMContentLoaded', function() {
    initFeedPagination();
  });

  /* ==========================================
     مقالات ذات صلة - Related Posts
  ========================================== */
  function initRelatedPosts() {
    var container = document.getElementById('related-posts-container');
    if (!container) return;

    var labelEls = document.querySelectorAll('.post-label-bottom, .post-label');
    var label = labelEls.length ? labelEls[0].textContent.trim() : '';

    if (!label) {
      var sec = document.querySelector('.related-posts-section');
      if (sec) sec.style.display = 'none';
      return;
    }

    var currentUrl = window.location.href;
    var feedUrl = '/feeds/posts/summary/-/' + encodeURIComponent(label) +
                  '?alt=json-in-script&max-results=6&callback=handleRelatedPosts';

    window.handleRelatedPosts = function(data) {
      var entries = (data.feed && data.feed.entry) ? data.feed.entry : [];
      var html = '';
      var count = 0;

      // دالة تهريب HTML آمنة - معرّفة خارج الحلقة
      function escapeHtml(text) {
        var map = {
          '&': '&amp;',
          '<': '&lt;',
          '>': '&gt;',
          '"': '&quot;',
          "'": '&#039;'
        };
        return text.replace(/[&<>"']/g, function(m) { return map[m]; });
      }

      for (var i = 0; i < entries.length && count < 3; i++) {
        var entry = entries[i];
        var url = '';
        for (var j = 0; j < entry.link.length; j++) {
          if (entry.link[j].rel === 'alternate') { url = entry.link[j].href; break; }
        }
        if (!url || url === currentUrl) continue;

        var title = entry.title ? entry.title.$t : '';
        if (!title) continue;

        var imgUrl = '';
        if (entry.media$thumbnail) {
          imgUrl = entry.media$thumbnail.url.replace('/s72-c/', '/w500-h300-p-k-no-nu/');
        }
        if (!imgUrl) imgUrl = 'https://lh3.googleusercontent.com/ULB6iBuCeTVvSjjjU1A-O8e9ZpVba6uvyhtiWRti_rBAs9yMYOFBujxriJRZ-A=w500-h300-p-k-no-nu';

        // استخراج الوصف من المقالة
        var description = '';
        if (entry.summary) {
          description = entry.summary.$t;
        } else if (entry.content) {
          description = entry.content.$t;
        }
        // إزالة HTML من الوصف وتقصيره
        if (description) {
          description = description.replace(/<[^>]*>/g, '');
          description = description.replace(/&nbsp;/g, ' ');
          description = description.replace(/&amp;/g, '&');
          description = description.replace(/&quot;/g, '"');
          description = description.substring(0, 100);
          if (description.length >= 100) {
            description += '...';
          }
        }

        var dateIso = entry.published ? entry.published.$t : '';
        var dateStr = dateIso ? getArabicRelativeTime(dateIso) : '';

        // تهريب المحتوى لمنع XSS
        var safeTitle = escapeHtml(title);
        var safeDesc = description ? escapeHtml(description) : '';
        var safeUrl = escapeHtml(url);
        var safeImgUrl = escapeHtml(imgUrl);

        html += '<a href="' + safeUrl + '" class="related-post-item">';
        html += '<div class="related-post-image-wrapper">';
        html += '<img src="' + safeImgUrl + '" alt="' + safeTitle + '" loading="lazy"/>';
        html += '<div class="related-post-overlay"></div>';
        html += '</div>';
        html += '<div class="related-post-content">';
        html += '<h4>' + safeTitle + '</h4>';
        if (safeDesc) {
          html += '<p class="related-post-excerpt">' + safeDesc + '</p>';
        }
        if (dateStr) {
          html += '<div class="related-post-date" data-date="' + dateIso + '">';
          html += '<svg viewBox="0 0 24 24"><path d="M19 4h-1V2h-2v2H8V2H6v2H5c-1.11 0-1.99.9-1.99 2L3 20c0 1.1.89 2 2 2h14c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 16H5V9h14v11z"/></svg>';
          html += '<span>' + escapeHtml(dateStr) + '</span>';
          html += '</div>';
        }
        html += '</div></a>';
        count++;
      }

      container.innerHTML = count > 0
        ? '<div class="related-posts-grid">' + html + '</div>'
        : '<div class="related-posts-empty">لا توجد مقالات ذات صلة</div>';
    };

    var s = document.createElement('script');
    s.src = feedUrl;
    s.async = true;
    s.onerror = function() {
      var sec = document.querySelector('.related-posts-section');
      if (sec) sec.style.display = 'none';
    };
    document.head.appendChild(s);
  }

  /* ==========================================
     تهيئة Pagination
  ========================================== */
  function initPagination() {
    var btn = document.getElementById('load-more-btn');
    if (!btn) return;
    btn.addEventListener('click', function(e) {
      e.preventDefault();
      window.loadMorePosts();
    });
  }

  /* ==========================================
     تشغيل عند DOMContentLoaded
  ========================================== */
  function init() {
    updateAllDates();
    initCommentReplyButtons();
    initReadingProgress();
    initLazyImages();
    convertMenuToDropdown(); // This stores originalMenuHTML first
    populateSidebarMenu(); // Then uses it
    initMobileMenu();
    initMobileDropdownToggle();
    initRelatedPosts();
    initPagination();
    initScrollReveal();
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

})();

