// دالة تحويل الصور العادية إلى lazy loading
function convertToLazyImages() {
  // Set alt text for snippet-thumbnail images from post title
  document.querySelectorAll('.snippet-thumbnail').forEach(function(container) {
    const img = container.querySelector('img');
    const postCard = container.closest('.post-card, article');
    if (img && postCard) {
      const titleEl = postCard.querySelector('.post-title, .post-title a');
      if (titleEl && titleEl.textContent && (!img.alt || img.alt === 'صورة')) {
        img.alt = titleEl.textContent.trim();
      }
    }
  });
  
  // معالجة الصور المميزة (LCP) - تحميل فوري
  document.querySelectorAll('.snippet-thumbnail img, .post-thumbnail-wrapper img').forEach(function(img) {
    if (!img.classList.contains('lazy-loaded')) {
      img.setAttribute('loading', 'eager');
      img.setAttribute('fetchpriority', 'high');
      img.classList.add('lazy-loaded', 'loaded');
    }
  });
  
  // Selectorfor all image containers that should have lazy loading
  const imageContainers = [
    '.post-thumbnail-wrapper',
    '.related-post-image-wrapper',
    '.post-placeholder-image',
    '.sidebar .widget img',
    '.blog-post img',
    '.post-body img',
    '.author-avatar',
    '.comment-avatar'
  ];

  // Process all images
  document.querySelectorAll('img').forEach(function(img) {
    // Skip featured images already processed
    if (img.hasAttribute('loading') && img.getAttribute('loading') === 'eager') return;
    
    // Skip small images and icons
    if (img.width < 50 || img.height < 50) return;
    
    // Skip images already processed
    if (img.classList.contains('lazy-loaded')) return;
    
    // Skip images without valid src
    if (!img.src || img.src === window.location.href || img.src === '') return;
    
    // Add alt attribute if missing (for SEO)
    if (!img.hasAttribute('alt') || img.getAttribute('alt') === '') {
      img.setAttribute('alt', '');
    }
    
    // Fix links without accessible text (for SEO)
    const parentLink = img.closest('a');
    if (parentLink) {
      // Add aria-label if link has no text
      if (!parentLink.textContent.trim() && !parentLink.getAttribute('aria-label') && !parentLink.getAttribute('title')) {
        const imgAlt = img.getAttribute('alt') || 'رابط صورة';
        parentLink.setAttribute('aria-label', imgAlt);
      }
    }
    
    // Mark as processed
    img.classList.add('lazy-loaded');
    
  });
}

