(function() {
  // التحقق بعد تحميل الصفحة
  setTimeout(function() {
    var blogPosts = document.querySelector('.blog-posts');
    var body = document.body;
    
    if (blogPosts) {
      var posts = blogPosts.querySelectorAll('.post-card, .post-outer');
      
      // If label page with no posts
      var isLabelPage = window.location.pathname.indexOf('/search/label/') !== -1;
      if (isLabelPage && (!posts || posts.length === 0)) {
        var emptyMsg = document.querySelector('.empty-state-message');
        if (emptyMsg) {
          emptyMsg.style.display = 'flex';
        }
        // إضافة كلاس body للصفحات الفارغة
        body.classList.add('empty-label-page');
      }
      
      // If search page with no posts
      var isSearchPage = window.location.pathname.indexOf('/search?q=') !== -1;
      if (isSearchPage && (!posts || posts.length === 0)) {
        var emptyMsg = document.querySelector('.empty-state-message');
        if (emptyMsg) {
          emptyMsg.style.display = 'flex';
        }
        // إضافة كلاس body للصفحات الفارغة
        body.classList.add('empty-search-page');
        }
      }
    }
  }, 1000); // انتظار لمدة ثانية للتأكد من تحميل جميع المقالات
})();

// ============================================
// Lazy Loading للصور في جسم المقالة
// ============================================
document.addEventListener('DOMContentLoaded', function() {
  // استخدام Intersection Observer للتحميل الكسول
  if ('IntersectionObserver' in window) {
    var lazyImages = document.querySelectorAll('.post-body img, .entry-content img');
    
    var imageObserver = new IntersectionObserver(function(entries, observer) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          var img = entry.target;
          
          // إذا كانت الصورة تحتوي على data-src
          if (img.dataset.src) {
            img.src = img.dataset.src;
            img.removeAttribute('data-src');
          }
          
          // إضافة فئة loaded بعد التحميل
          img.onload = function() {
            img.classList.add('loaded');
          };
          
          // إذا كانت الصورة محملة بالفعل
          if (img.complete) {
            img.classList.add('loaded');
          }
          
          imageObserver.unobserve(img);
        }
      });
    }, {
      rootMargin: '50px 0px',
      threshold: 0.01
    });
    
    lazyImages.forEach(function(img) {
      imageObserver.observe(img);
    });
  } else {
    // للمتصفحات القديمة - تحميل فوري
    var lazyImages = document.querySelectorAll('.post-body img, .entry-content img');
    lazyImages.forEach(function(img) {
      img.classList.add('loaded');
    });
  }
});

// ============================================
// تأثير حركة للعناصر عند التمرير
// ============================================
document.addEventListener('DOMContentLoaded', function() {
  if ('IntersectionObserver' in window) {
    var animatedElements = document.querySelectorAll('.author-box, .share-buttons, .post-tags-bottom, .related-posts-section');
    
    var elementObserver = new IntersectionObserver(function(entries, observer) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          entry.target.style.opacity = '1';
          entry.target.style.transform = 'translateY(0)';
          elementObserver.unobserve(entry.target);
        }
      });
    }, {
      rootMargin: '0px 0px -50px 0px',
      threshold: 0.1
    });
    
    animatedElements.forEach(function(el) {
      // إضافة الأنماط الأولية
      el.style.opacity = '0';
      el.style.transform = 'translateY(30px)';
      el.style.transition = 'opacity 0.6s ease, transform 0.6s ease';
      elementObserver.observe(el);
    });
  }
});
