/* ==========================================
   Enhanced Comment System JavaScript
   نظام التعليقات المحسن - JavaScript
========================================== */

// Comment system state management
var CommentSystem = {
  isSubmitting: false,
  currentReplyId: null,
  
  // Show loading state
  showLoading: function() {
    var loadingEl = document.getElementById('comment-loading');
    var errorEl = document.getElementById('comment-error');
    var successEl = document.getElementById('comment-success');
    
    if (loadingEl) {
      loadingEl.classList.add('active');
    }
    if (errorEl) errorEl.classList.remove('active');
    if (successEl) successEl.classList.remove('active');
    
    this.isSubmitting = true;
  },
  
  // Hide loading state
  hideLoading: function() {
    var loadingEl = document.getElementById('comment-loading');
    if (loadingEl) {
      loadingEl.classList.remove('active');
    }
    this.isSubmitting = false;
  },
  
  // Show error message
  showError: function(message) {
    var errorEl = document.getElementById('comment-error');
    var errorTextEl = document.getElementById('comment-error-text');
    var loadingEl = document.getElementById('comment-loading');
    var successEl = document.getElementById('comment-success');
    
    if (loadingEl) loadingEl.classList.remove('active');
    if (successEl) successEl.classList.remove('active');
    
    if (errorEl && errorTextEl) {
      errorTextEl.textContent = message || 'حدث خطأ أثناء نشر التعليق. يرجى المحاولة مرة أخرى.';
      errorEl.classList.add('active');
      
      // Auto-hide after 5 seconds
      setTimeout(function() {
        errorEl.classList.remove('active');
      }, 5000);
    }
    
    this.isSubmitting = false;
  },
  
  // Show success message
  showSuccess: function() {
    var successEl = document.getElementById('comment-success');
    var errorEl = document.getElementById('comment-error');
    var loadingEl = document.getElementById('comment-loading');
    
    if (loadingEl) loadingEl.classList.remove('active');
    if (errorEl) errorEl.classList.remove('active');
    
    if (successEl) {
      successEl.classList.add('active');
      
      // Auto-hide after 3 seconds
      setTimeout(function() {
        successEl.classList.remove('active');
      }, 3000);
    }
    
    this.isSubmitting = false;
  },
  
  // Update comment counter
  updateCounter: function() {
    var counterEl = document.getElementById('comment-counter');
    if (counterEl) {
      var countEl = counterEl.querySelector('.comment-count-number');
      if (countEl) {
        var currentCount = parseInt(countEl.textContent) || 0;
        countEl.textContent = currentCount + 1;
      }
    }
  },
  
  // Validate comment before submission
  validate: function() {
    var editor = document.getElementById('comment-editor');
    if (!editor) return true;
    
    // Blogger handles validation internally in the iframe
    return true;
  }
};

// Main function to handle reply button clicks - called from onclick
function onReply(commentId, formId) {
  var commentEditor = document.getElementById('comment-editor');
  if (!commentEditor) {
    // Try to find iframe in the comment editor container
    var container = document.getElementById('comment-editor-container');
    if (container) {
      commentEditor = container.querySelector('iframe');
    }
  }
  
  if (commentEditor) {
    // Get current iframe src
    var currentSrc = commentEditor.src || commentEditor.getAttribute('src') || '';
    
    // Remove existing parentID from iframe src if present
    if (currentSrc.indexOf('parentID') > -1) {
      currentSrc = currentSrc.replace(/&parentID=[^&]*/, '');
    }
    
    // Add parentID to iframe src (ensure proper URL format)
    var separator = currentSrc.indexOf('?') > -1 ? '&' : '?';
    commentEditor.src = currentSrc + separator + 'parentID=' + commentId;
    
    // Store current reply ID
    CommentSystem.currentReplyId = commentId;
    
    // Add reply indicator class
    var container = document.getElementById('comment-editor-container');
    if (container) {
      container.classList.add('reply-form');
    }
    
    // Ensure the comment editor is visible
    if (container) {
      container.style.display = 'block';
    }
    
    // Show comment editor if it's hidden
    commentEditor.style.display = 'block';
    
    // Scroll to comment editor with smooth animation
    if (container) {
      container.scrollIntoView({ behavior: 'smooth', block: 'center' });
    } else {
      commentEditor.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
    
    // Clear any previous messages
    var errorEl = document.getElementById('comment-error');
    var successEl = document.getElementById('comment-success');
    if (errorEl) errorEl.classList.remove('active');
    if (successEl) successEl.classList.remove('active');
    
    return false;
  }
  
  // Fallback: allow default behavior
  return true;
}

// Legacy function for compatibility
function handleReply(button) {
  var commentId = button.getAttribute('data-comment-id');
  return onReply(commentId, null);
}

// Enhanced comment submission handler
function handleCommentSubmit() {
  if (CommentSystem.isSubmitting) {
    return false;
  }
  
  if (!CommentSystem.validate()) {
    CommentSystem.showError('يرجى إدخال تعليق صحيح.');
    return false;
  }
  
  CommentSystem.showLoading();
  return true;
}

// Monitor comment submission via iframe
function initCommentMonitor() {
  var commentEditor = document.getElementById('comment-editor');
  if (!commentEditor) return;
  
  // Check for iframe load events (comment submission)
  commentEditor.addEventListener('load', function() {
    // Comment was submitted - hide loading
    setTimeout(function() {
      CommentSystem.hideLoading();
      
      // Check if comment was successful (Blogger redirects after submission)
      var src = commentEditor.src || '';
      if (src.indexOf('parentID') === -1) {
        // Regular comment or reply submitted
        CommentSystem.showSuccess();
        CommentSystem.updateCounter();
        
        // Reset form state
        var container = document.getElementById('comment-editor-container');
        if (container) {
          container.classList.remove('reply-form');
        }
        CommentSystem.currentReplyId = null;
      }
    }, 1000);
  });
}

// Initialize reply buttons when DOM is ready
document.addEventListener('DOMContentLoaded', function() {
  // Add click handlers for all reply buttons
  var replyButtons = document.querySelectorAll('.comment-reply');
  replyButtons.forEach(function(button) {
    button.addEventListener('click', function(e) {
      e.preventDefault();
      var commentId = this.getAttribute('data-comment-id');
      onReply(commentId, null);
      return false;
    });
  });
  
  // Initialize comment monitor
  initCommentMonitor();
  
  // Add focus styles for better accessibility
  var commentEditor = document.getElementById('comment-editor');
  if (commentEditor) {
    commentEditor.setAttribute('tabindex', '0');
  }
  
  // Add cancel reply functionality
  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') {
      var container = document.getElementById('comment-editor-container');
      if (container && container.classList.contains('reply-form')) {
        var commentEditor = document.getElementById('comment-editor');
        if (commentEditor) {
          var currentSrc = commentEditor.src || '';
          if (currentSrc.indexOf('parentID') > -1) {
            currentSrc = currentSrc.replace(/&parentID=[^&]*/, '');
            commentEditor.src = currentSrc;
          }
        }
        container.classList.remove('reply-form');
        CommentSystem.currentReplyId = null;
      }
    }
  });
});

// Handle Blogger's comment deletion
function initCommentDeletionMonitor() {
  // Monitor for comment deletion links
  var deleteLinks = document.querySelectorAll('.comment-delete, a[href*="delete-comment"]');
  deleteLinks.forEach(function(link) {
    link.addEventListener('click', function(e) {
      if (!confirm('هل أنت متأكد من حذف هذا التعليق؟')) {
        e.preventDefault();
        return false;
      }
    });
  });
}

// Initialize on page load
window.addEventListener('load', function() {
  initCommentDeletionMonitor();
});
